component.schema:
{
 "description": "NVIDIADriver is the Schema for the nvidiadrivers API",
 "properties": {
  "spec": {
   "description": "NVIDIADriverSpec defines the desired state of NVIDIADriver",
   "properties": {
    "annotations": {
     "additionalProperties": {
      "type": "string"
     },
     "description": "Optional: Annotations is an unstructured key value map stored with a resource that may be\nset by external tools to store and retrieve arbitrary metadata. They are not\nqueryable and should be preserved when modifying objects.",
     "type": "object"
    },
    "args": {
     "description": "Optional: List of arguments",
     "items": {
      "type": "string"
     },
     "type": "array"
    },
    "certConfig": {
     "description": "Optional: Custom certificates configuration for NVIDIA Driver container",
     "properties": {
      "name": {
       "type": "string"
      }
     },
     "type": "object"
    },
    "driverType": {
     "default": "gpu",
     "description": "DriverType defines NVIDIA driver type",
     "enum": [
      "gpu",
      "vgpu",
      "vgpu-host-manager"
     ],
     "type": "string",
     "x-kubernetes-validations": [
      {
       "message": "driverType is an immutable field. Please create a new NvidiaDriver resource instead when you want to change this setting.",
       "rule": "self == oldSelf"
      }
     ]
    },
    "env": {
     "description": "Optional: List of environment variables",
     "items": {
      "description": "EnvVar represents an environment variable present in a Container.",
      "properties": {
       "name": {
        "description": "Name of the environment variable.",
        "type": "string"
       },
       "value": {
        "description": "Value of the environment variable.",
        "type": "string"
       }
      },
      "required": [
       "name"
      ],
      "type": "object"
     },
     "type": "array"
    },
    "gdrcopy": {
     "description": "GDRCopy defines the spec for GDRCopy driver",
     "properties": {
      "args": {
       "description": "Optional: List of arguments",
       "items": {
        "type": "string"
       },
       "type": "array"
      },
      "enabled": {
       "description": "Enabled indicates if GDRCopy is enabled through GPU operator",
       "type": "boolean"
      },
      "env": {
       "description": "Optional: List of environment variables",
       "items": {
        "description": "EnvVar represents an environment variable present in a Container.",
        "properties": {
         "name": {
          "description": "Name of the environment variable.",
          "type": "string"
         },
         "value": {
          "description": "Value of the environment variable.",
          "type": "string"
         }
        },
        "required": [
         "name"
        ],
        "type": "object"
       },
       "type": "array"
      },
      "image": {
       "description": "GDRCopy driver image name",
       "pattern": "[a-zA-Z0-9\\-]+",
       "type": "string"
      },
      "imagePullPolicy": {
       "description": "Image pull policy",
       "type": "string"
      },
      "imagePullSecrets": {
       "description": "Image pull secrets",
       "items": {
        "type": "string"
       },
       "type": "array"
      },
      "repository": {
       "description": "GDRCopy diver image repository",
       "type": "string"
      },
      "version": {
       "description": "GDRCopy driver image tag",
       "type": "string"
      }
     },
     "type": "object"
    },
    "gds": {
     "description": "GPUDirectStorage defines the spec for GDS driver",
     "properties": {
      "args": {
       "description": "Optional: List of arguments",
       "items": {
        "type": "string"
       },
       "type": "array"
      },
      "enabled": {
       "description": "Enabled indicates if GPUDirect Storage is enabled through GPU operator",
       "type": "boolean"
      },
      "env": {
       "description": "Optional: List of environment variables",
       "items": {
        "description": "EnvVar represents an environment variable present in a Container.",
        "properties": {
         "name": {
          "description": "Name of the environment variable.",
          "type": "string"
         },
         "value": {
          "description": "Value of the environment variable.",
          "type": "string"
         }
        },
        "required": [
         "name"
        ],
        "type": "object"
       },
       "type": "array"
      },
      "image": {
       "description": "NVIDIA GPUDirect Storage Driver image name",
       "pattern": "[a-zA-Z0-9\\-]+",
       "type": "string"
      },
      "imagePullPolicy": {
       "description": "Image pull policy",
       "type": "string"
      },
      "imagePullSecrets": {
       "description": "Image pull secrets",
       "items": {
        "type": "string"
       },
       "type": "array"
      },
      "repository": {
       "description": "NVIDIA GPUDirect Storage Driver image repository",
       "type": "string"
      },
      "version": {
       "description": "NVIDIA GPUDirect Storage Driver image tag",
       "type": "string"
      }
     },
     "type": "object"
    },
    "hostNetwork": {
     "description": "HostNetwork indicates whether the Driver pod uses the host's network namespace.",
     "type": "boolean"
    },
    "image": {
     "default": "nvcr.io/nvidia/driver",
     "description": "NVIDIA Driver container image name",
     "type": "string"
    },
    "imagePullPolicy": {
     "description": "Image pull policy",
     "type": "string"
    },
    "imagePullSecrets": {
     "description": "Image pull secrets",
     "items": {
      "type": "string"
     },
     "type": "array"
    },
    "kernelModuleConfig": {
     "description": "Optional: Kernel module configuration parameters for the NVIDIA Driver",
     "properties": {
      "name": {
       "type": "string"
      }
     },
     "type": "object"
    },
    "kernelModuleType": {
     "default": "auto",
     "description": "KernelModuleType represents the type of driver kernel modules to be used when installing the GPU driver.\nAccepted values are auto, proprietary and open. NOTE: If auto is chosen, it means that the recommended kernel module\ntype is chosen based on the GPU devices on the host and the driver branch used",
     "enum": [
      "auto",
      "open",
      "proprietary"
     ],
     "type": "string"
    },
    "labels": {
     "additionalProperties": {
      "type": "string"
     },
     "description": "Optional: Map of string keys and values that can be used to organize and categorize\n(scope and select) objects. May match selectors of replication controllers\nand services.",
     "type": "object"
    },
    "licensingConfig": {
     "description": "Optional: Licensing configuration for NVIDIA vGPU licensing",
     "properties": {
      "name": {
       "description": "Deprecated: ConfigMapName has been deprecated in favour of SecretName. Please use secrets to handle the licensing server configuration more securely",
       "type": "string"
      },
      "nlsEnabled": {
       "description": "NLSEnabled indicates if NVIDIA Licensing System is used for licensing.",
       "type": "boolean"
      },
      "secretName": {
       "type": "string"
      }
     },
     "type": "object"
    },
    "livenessProbe": {
     "description": "NVIDIA Driver container liveness probe settings",
     "properties": {
      "failureThreshold": {
       "description": "Minimum consecutive failures for the probe to be considered failed after having succeeded.\nDefaults to 3. Minimum value is 1.",
       "format": "int32",
       "minimum": 1,
       "type": "integer"
      },
      "initialDelaySeconds": {
       "description": "Number of seconds after the container has started before liveness probes are initiated.\nMore info: https://kubernetes.io/docs/concepts/workloads/pods/pod-lifecycle#container-probes",
       "format": "int32",
       "type": "integer"
      },
      "periodSeconds": {
       "description": "How often (in seconds) to perform the probe.\nDefault to 10 seconds. Minimum value is 1.",
       "format": "int32",
       "minimum": 1,
       "type": "integer"
      },
      "successThreshold": {
       "description": "Minimum consecutive successes for the probe to be considered successful after having failed.\nDefaults to 1. Must be 1 for liveness and startup. Minimum value is 1.",
       "format": "int32",
       "minimum": 1,
       "type": "integer"
      },
      "timeoutSeconds": {
       "description": "Number of seconds after which the probe times out.\nDefaults to 1 second. Minimum value is 1.\nMore info: https://kubernetes.io/docs/concepts/workloads/pods/pod-lifecycle#container-probes",
       "format": "int32",
       "minimum": 1,
       "type": "integer"
      }
     },
     "type": "object"
    },
    "manager": {
     "description": "Manager represents configuration for NVIDIA Driver Manager initContainer",
     "properties": {
      "env": {
       "description": "Optional: List of environment variables",
       "items": {
        "description": "EnvVar represents an environment variable present in a Container.",
        "properties": {
         "name": {
          "description": "Name of the environment variable.",
          "type": "string"
         },
         "value": {
          "description": "Value of the environment variable.",
          "type": "string"
         }
        },
        "required": [
         "name"
        ],
        "type": "object"
       },
       "type": "array"
      },
      "image": {
       "description": "Image represents NVIDIA Driver Manager image name",
       "pattern": "[a-zA-Z0-9\\-]+",
       "type": "string"
      },
      "imagePullPolicy": {
       "description": "Image pull policy",
       "type": "string"
      },
      "imagePullSecrets": {
       "description": "Image pull secrets",
       "items": {
        "type": "string"
       },
       "type": "array"
      },
      "repository": {
       "description": "Repository represents Driver Managerrepository path",
       "type": "string"
      },
      "version": {
       "description": "Version represents NVIDIA Driver Manager image tag(version)",
       "type": "string"
      }
     },
     "type": "object"
    },
    "nodeAffinity": {
     "description": "Affinity specifies node affinity rules for driver pods",
     "properties": {
      "preferredDuringSchedulingIgnoredDuringExecution": {
       "description": "The scheduler will prefer to schedule pods to nodes that satisfy\nthe affinity expressions specified by this field, but it may choose\na node that violates one or more of the expressions. The node that is\nmost preferred is the one with the greatest sum of weights, i.e.\nfor each node that meets all of the scheduling requirements (resource\nrequest, requiredDuringScheduling affinity expressions, etc.),\ncompute a sum by iterating through the elements of this field and adding\n\"weight\" to the sum if the node matches the corresponding matchExpressions; the\nnode(s) with the highest sum are the most preferred.",
       "items": {
        "description": "An empty preferred scheduling term matches all objects with implicit weight 0\n(i.e. it's a no-op). A null preferred scheduling term matches no objects (i.e. is also a no-op).",
        "properties": {
         "preference": {
          "description": "A node selector term, associated with the corresponding weight.",
          "properties": {
           "matchExpressions": {
            "description": "A list of node selector requirements by node's labels.",
            "items": {
             "description": "A node selector requirement is a selector that contains values, a key, and an operator\nthat relates the key and values.",
             "properties": {
              "key": {
               "description": "The label key that the selector applies to.",
               "type": "string"
              },
              "operator": {
               "description": "Represents a key's relationship to a set of values.\nValid operators are In, NotIn, Exists, DoesNotExist. Gt, and Lt.",
               "type": "string"
              },
              "values": {
               "description": "An array of string values. If the operator is In or NotIn,\nthe values array must be non-empty. If the operator is Exists or DoesNotExist,\nthe values array must be empty. If the operator is Gt or Lt, the values\narray must have a single element, which will be interpreted as an integer.\nThis array is replaced during a strategic merge patch.",
               "items": {
                "type": "string"
               },
               "type": "array",
               "x-kubernetes-list-type": "atomic"
              }
             },
             "required": [
              "key",
              "operator"
             ],
             "type": "object"
            },
            "type": "array",
            "x-kubernetes-list-type": "atomic"
           },
           "matchFields": {
            "description": "A list of node selector requirements by node's fields.",
            "items": {
             "description": "A node selector requirement is a selector that contains values, a key, and an operator\nthat relates the key and values.",
             "properties": {
              "key": {
               "description": "The label key that the selector applies to.",
               "type": "string"
              },
              "operator": {
               "description": "Represents a key's relationship to a set of values.\nValid operators are In, NotIn, Exists, DoesNotExist. Gt, and Lt.",
